import json
import re

data = _items[0]["json"]
out = data.get("stdout")
err = data.get("stderr")

# 1. Если скрипт ничего не вывел — сразу ошибка
if not out:
    msg = f"Ошибка выполнения: {err[:500]}" if err else "Скрипт ничего не вывел."
    return [{"json": {"output": msg, "status": "error", "stderr": err[:500] or None}}]

# 2. Вытаскиваем JSON-объект из вывода (мог быть мусор от sklearn перед ним)
json_str = out[out.find("{"):]
parsed = json.loads(json_str)

try:
    parsed = json.loads(json_str)
except Exception as e:
    parsed = {"status": "parse_error", "error": str(e), "raw": out[:500]}

# 3. Сообщение для агента
if parsed.get("status") == "success":
    agent_response = parsed.get("summary")
else:
    agent_response = f"Ошибка при обучении модели: {parsed.get('error') or 'неизвестная ошибка'}"

# 4. Форматируем метрики регрессии
raw_metrics = parsed.get("train_metrics") or {}
train_metrics = {}

for key, fmt in [("rmse", ".2f"), ("mae", ".2f"), ("r2", ".4f")]:
    value = raw_metrics.get(key)
    if isinstance(value, (int, float)):
        train_metrics[key] = format(value, fmt)
    else:
        train_metrics[key] = "N/A"

# 5. Собираем результат
return [{
    "json": {
        "output": agent_response,
        "status": parsed.get("status"),
        "summary": parsed.get("summary"),
        "candidate_path": parsed.get("candidate_path"),
        "model_type": parsed.get("model_type"),
        "train_time_sec": parsed.get("train_time_sec"),
        "feature_count": parsed.get("feature_count"),
        "train_metrics": train_metrics,
    }
}]
